<script setup lang="ts">
import { ref,onMounted } from 'vue';import { fetchOrder,payOrder,completeMockPayment } from '@/services/trade';import { formatMoney } from '@/lib/currency';import type { TradeOrder,PaymentIntent } from '@/types/trade'
const props=defineProps<{orderId:number}>(),order=ref<TradeOrder|null>(null),intent=ref<PaymentIntent|null>(null),errorMessage=ref('');async function load(){order.value=await fetchOrder(props.orderId)}async function pay(){try{intent.value=await payOrder(props.orderId)}catch(e){errorMessage.value=e instanceof Error?e.message:'支付发起失败'}}async function complete(){try{order.value=await completeMockPayment(props.orderId);intent.value=null}catch(e){errorMessage.value=e instanceof Error?e.message:'模拟支付失败'}}onMounted(()=>load().catch(e=>errorMessage.value=e.message))
</script><template><section v-if="order" class="page-section"><div class="page-header"><div><p class="eyebrow">订单 {{order.orderNo}}</p><h1>{{order.dealTitle}}</h1><p>{{order.shopName}} · {{formatMoney(order.amount,order.currency)}} · {{order.payStatusText}}</p></div></div><p v-if="errorMessage" class="feedback is-error">{{errorMessage}}</p><div class="hero-actions"><button v-if="order.payStatus===0&&!intent" class="primary-button" @click="pay">发起支付</button><button v-if="intent" class="primary-button" @click="complete">模拟 {{intent.channel}} 支付成功</button></div><section v-if="order.coupons?.length" class="content-card"><h2>券码</h2><div class="tag-row"><span v-for="c in order.coupons" :key="c.id">{{c.code}} · {{c.statusText}}</span></div></section></section></template>
